import{_ as a,o,c as i,ae as n}from"./chunks/framework.CyZiF_rV.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pl/offline/automatyczne-okreslanie-trybu-offline.md","filePath":"pl/offline/automatyczne-okreslanie-trybu-offline.md"}'),t={name:"pl/offline/automatyczne-okreslanie-trybu-offline.md"};function r(s,e,d,l,c,y){return o(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="automatyczne-okreslanie-trybu-wysyłki-offline" tabindex="-1">Automatyczne określanie trybu wysyłki offline <a class="header-anchor" href="#automatyczne-okreslanie-trybu-wysyłki-offline" aria-label="Permalink to &quot;Automatyczne określanie trybu wysyłki offline&quot;">​</a></h2><p>04.10.2025</p><p>W przypadku faktur przesyłanych jako online (<code>offlineMode: false</code>) system KSeF może przypisać im tryb offline - na podstawie porównania daty wystawienia z datą przyjęcia do przetwarzania.</p><h2 id="algorytm-mechanizmu" tabindex="-1">Algorytm mechanizmu <a class="header-anchor" href="#algorytm-mechanizmu" aria-label="Permalink to &quot;Algorytm mechanizmu&quot;">​</a></h2><p>Dla faktur wysyłanych jako <code>offlineMode: false</code> system porównuje:</p><ul><li><strong>datę wystawienia</strong> faktury (<code>issueDate</code>, np. <code>P_1</code> dla faktury zgodnej z FA(3)),</li><li><strong>datę przyjęcia</strong> faktury w systemie KSeF do dalszego przetwarzania (<code>invoicingDate</code>).</li></ul><p>Reguły:</p><ul><li>Jeśli dzień kalendarzowy z <code>issueDate</code> jest wcześniejszy niż dzień kalendarzowy z <code>invoicingDate</code> (porównanie po dacie, nie po godzinie), system automatycznie oznacza fakturę jako <strong>offline</strong>, nawet jeśli nie była tak zadeklarowana.</li><li>Jeśli dzień <code>issueDate</code> i dzień <code>invoicingDate</code> są takie same, faktura pozostaje <strong>online</strong>.</li></ul><p>Wartość <code>invoicingDate</code> zależy od trybu przesyłki:</p><ul><li><strong>sesja wsadowa</strong> - <code>invoicingDate</code> to moment otwarcia sesji (równy <code>dateCreated</code> zwracanemu w statusie sesji - GET <code>/sessions/{referenceNumber}</code>),</li><li><strong>sesja interaktywna</strong> - <code>invoicingDate</code> to moment przesłania faktury.</li></ul><p>To oznacza, że jeśli np. faktura została wystawiona 2025-10-03 (<code>P_1</code>), a przesłana 2025-10-04 o godzinie 00:00:01, to mimo offlineMode: false zostanie oznaczona jako faktura offline.</p><h2 id="przykłady" tabindex="-1">Przykłady <a class="header-anchor" href="#przykłady" aria-label="Permalink to &quot;Przykłady&quot;">​</a></h2><p><strong>Sesja wsadowa</strong> otwarta o 23:59:59 3 października: Nawet jeśli paczka będzie przesłana po północy, faktury pozostaną online – ponieważ <code>invoicingDate</code> to 3 października (data otwarcia sesji).</p><p><strong>Sesja interaktywna</strong> rozpoczęta o 23:59:59 3 października, a faktury zostały przesłane po północy: Jeżeli <code>P_1</code> = 2025-10-03, system oznaczy je jako offline – ponieważ dzień <code>P_1</code> jest wcześniejszy niż dzień przesłania.</p><h2 id="powiazane-dokumenty" tabindex="-1">Powiązane dokumenty <a class="header-anchor" href="#powiazane-dokumenty" aria-label="Permalink to &quot;Powiązane dokumenty&quot;">​</a></h2><ul><li><a href="./../tryby-offline.html">Tryby offline</a></li></ul>',16)])])}const f=a(t,[["render",r]]);export{p as __pageData,f as default};
